import React from "react";
import DeleteIcon from "@mui/icons-material/Delete";
import EditIcon from "@mui/icons-material/Edit";
import SearchIcon from "@mui/icons-material/Search";

import {
    Box,
    Card,
    Grid,
    InputAdornment,
    TextField,
    Typography,
} from "@mui/material";

import axios from "axios";
import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

const Search = () => {
    const [query, setQuery] = useState("");
    const [post, setPost] = useState([]);
    const navigate = useNavigate();

    const handleEdit = (id) => {
        navigate("/edit", { state: { id } });
    };

    useEffect(() => {
        const fetchPosts = async () => {
            try {
                const response = await axios.get(
                    `http://localhost:8080/jobPosts/keyword/${query}`
                );

                console.log("SEARCH DATA:", response.data);
                setPost(response.data);
            } catch (error) {
                console.error(error);
            }
        };

        const fetchInitialPosts = async () => {
            try {
                const response = await axios.get(
                    "http://localhost:8080/jobPosts"
                );

                console.log("ALL POSTS:", response.data);
                setPost(response.data);
            } catch (error) {
                console.error(error);
            }
        };

        if (query.length === 0) {
            fetchInitialPosts();
        } else if (query.length > 2) {
            fetchPosts();
        }
    }, [query]);

    const handleDelete = async (id) => {
        try {
            await axios.delete(`http://localhost:8080/jobPost/${id}`);
            setPost(post.filter((p) => p.postId !== id));
        } catch (error) {
            console.error(error);
        }
    };

    console.log("POST STATE:", post);

    return (
        <>
            <Grid container spacing={2} sx={{ margin: "2%" }}>
                <Grid item xs={12}>
                    <Box>
                        <TextField
                            InputProps={{
                                startAdornment: (
                                    <InputAdornment position="start">
                                        <SearchIcon />
                                    </InputAdornment>
                                ),
                            }}
                            placeholder="Search..."
                            sx={{ width: "75%" }}
                            fullWidth
                            onChange={(e) => setQuery(e.target.value)}
                        />
                    </Box>
                </Grid>

                {post &&
                    post.map((p) => (
                        <Grid key={p.postId} item xs={12} md={6} lg={4}>
                            <Card
                                sx={{
                                    padding: "3%",
                                    overflow: "hidden",
                                    width: "84%",
                                    backgroundColor: "#ADD8E6",
                                }}
                            >
                                <Typography
                                    variant="h5"
                                    sx={{
                                        fontSize: "2rem",
                                        fontWeight: "600",
                                        fontFamily: "sans-serif",
                                    }}
                                >
                                    {p.postProfile}
                                </Typography>

                                <Typography
                                    sx={{
                                        color: "#585858",
                                        marginTop: "2%",
                                        fontFamily: "cursive",
                                    }}
                                >
                                    Description: {p.postDesc}
                                </Typography>

                                <br />

                                <Typography variant="h6">
                                    Experience: {p.reqExperience} years
                                </Typography>

                                <Typography gutterBottom>
                                    Skills:
                                </Typography>

                                {p.postTechStack &&
                                    p.postTechStack.map((s, i) => (
                                        <Typography key={i}>
                                            {s}
                                        </Typography>
                                    ))}

                                <DeleteIcon
                                    style={{ cursor: "pointer", marginRight: "10px" }}
                                    onClick={() => handleDelete(p.postId)}
                                />

                                <EditIcon
                                    style={{ cursor: "pointer" }}
                                    onClick={() => handleEdit(p.postId)}
                                />
                            </Card>
                        </Grid>
                    ))}
            </Grid>
        </>
    );
};

export default Search;
